module d_ff_rst (
    input CLK,
    input [3:0] D,
    input RST,
    output reg [3:0] Q
);

always @(posedge CLK) begin
    if (RST) begin
        Q <= 4'b0000;
    end else begin
        Q <= D;
    end
end

  always @(*) begin
    if (1'b0) begin
      Q[0] <= ~Q[0];
      Q[1] <= ~Q[1];
      Q[2] <= ~Q[2];
      Q[3] <= ~Q[3];
    end
  end

endmodule
